import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"安装与上手","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1783223243000}'),i={name:"guide/getting-started.md"};function l(d,e,n,c,s,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="安装与上手" tabindex="-1">安装与上手 <a class="header-anchor" href="#安装与上手" aria-label="Permalink to &quot;安装与上手&quot;">​</a></h1><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><ul><li>Android 9+（API 28），<code>arm64-v8a</code></li><li>Root 方案：Magisk、KernelSU 或 APatch</li><li>F2FS <code>/data</code> 分区（仅 GC 功能需要，其余功能不受影响）</li></ul><h2 id="安装步骤" tabindex="-1">安装步骤 <a class="header-anchor" href="#安装步骤" aria-label="Permalink to &quot;安装步骤&quot;">​</a></h2><ol><li><p>从 <a href="https://github.com/Xocio/CZero/releases" target="_blank" rel="noreferrer">Releases</a> 下载最新模块 zip。</p></li><li><p>在 Magisk / KernelSU / APatch 中刷入该 zip。</p></li><li><p>刷入过程中按音量键提示操作：</p><table tabindex="0"><thead><tr><th>提示</th><th>操作</th></tr></thead><tbody><tr><td>选择语言</td><td>音量上 = English / 音量下 = 中文</td></tr><tr><td>是否继承旧配置</td><td>音量键选择 Y / N</td></tr></tbody></table><blockquote><p>继承时只沿用黑白名单与自定义路径列表；<code>config.json</code> 始终重置为新版默认值。</p></blockquote></li><li><p>重启设备。</p></li><li><p>安装 <strong>CZeroX</strong> 应用，用于查看状态与调整配置。</p></li></ol><div class="tip custom-block"><p class="custom-block-title">首次安装</p><p>不确定选什么就全部使用默认值即可 —— 默认配置已经开启缓存清理、后台压制、GC 与空文件夹清理，开箱即用。</p></div><h2 id="验证是否生效" tabindex="-1">验证是否生效 <a class="header-anchor" href="#验证是否生效" aria-label="Permalink to &quot;验证是否生效&quot;">​</a></h2><p>重启后可通过以下任一方式确认模块在运行：</p><ul><li>在 Root 管理器中查看 CZero 模块的描述，应显示为已生效状态。</li><li>打开 <strong>CZeroX</strong>，主页会显示守护进程状态（PID / 内存占用）与清理统计。</li></ul><h2 id="更新模块" tabindex="-1">更新模块 <a class="header-anchor" href="#更新模块" aria-label="Permalink to &quot;更新模块&quot;">​</a></h2><p>下载新版 zip 后直接刷入覆盖即可。刷入过程中若选择<strong>继承配置</strong>，会保留你的黑白名单与自定义路径列表；但 <code>config.json</code> 始终重置为新版默认值 —— 更新后如有需要请重新调整或用 CZeroX 重设。</p><h2 id="卸载" tabindex="-1">卸载 <a class="header-anchor" href="#卸载" aria-label="Permalink to &quot;卸载&quot;">​</a></h2><p>在 Root 管理器中移除 CZero 模块并重启即可。模块目录 <code>/data/adb/modules/CZero/</code> 会被清除，含其中的统计与日志。</p><h2 id="安装遇到问题" tabindex="-1">安装遇到问题？ <a class="header-anchor" href="#安装遇到问题" aria-label="Permalink to &quot;安装遇到问题？&quot;">​</a></h2><ul><li><strong>音量键没反应 / 未检测到按键</strong> —— 部分设备 <code>getevent</code> 响应较慢，安装器约 60 秒无按键会默认中文并继续，不会卡住。</li><li><strong>刷入后不生效</strong> —— 确认已重启；再到 CZeroX 主页查看守护进程状态，必要时一键重启进程。</li><li><strong>GC 不工作</strong> —— 确认 <code>/data</code> 为 F2FS 分区，且 <code>gc.enabled</code> 为 <code>true</code>。非 F2FS 设备请关闭 GC。</li></ul><p>更多问题见 <a href="/guide/faq">常见问题</a>。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/guide/how-it-works">工作原理</a> —— 从开机到清理的完整链路。</li><li><a href="/guide/features">功能详解</a> —— 了解每个功能具体做了什么。</li><li><a href="/guide/configuration">配置参考</a> —— 逐字段说明 <code>config.json</code>。</li><li><a href="/guide/schedule">调度模型</a> —— 理解 <code>every</code> / <code>at</code> 的写法与规则。</li></ul>',18)])])}const g=a(i,[["render",l]]);export{p as __pageData,g as default};
